from jinja2 import Template


def render_user_profile_bio(bio_content: str) -> str:
    """
    Render the user's bio section using Jinja2 template.

    Args:
        bio_content: The user-provided bio text. For example: 'Lover of coffee and code.'

    Returns:
        The rendered HTML snippet of the user's bio.
    """
    # Simple template that wraps the bio content in a div with appropriate styling
    template_str = """
    <div class="user-bio" style="
        font-family: Arial, sans-serif;
        font-size: 14px;
        line-height: 1.5;
        color: #333;
        padding: 10px;
        border-radius: 5px;
        background-color: #f9f9f9;
        margin: 10px 0;
    ">
        {{ bio_content }}
    </div>
    """

    template = Template(template_str)
    rendered_html = template.render(bio_content=bio_content)

    return rendered_html
